const ProducItem = () => {
  return (
    <div className="item producItem">
      <div className="imgWrapper">
        <img src={sp1} className="w-100" />
        <span className="badge bg-primary"> 30%</span>
        <div className="actions">
          <Button></Button>
        </div>
      </div>
      <div className="info">
        <h4> MLB - Áo thun unisex cổ tròn tay ngắn hiện đại</h4>
        <span className="text-success d-block"> Sẵn hàng</span>
        <Rating
          className="mt-2 mb-2"
          name="read-only"
          value={5}
          readOnly
          size="small"
          precision={0.1}
        />
        <div className="d-flex">
          <span className="oldPrice"> 499.000 VNĐ</span>
          <span className="newPrice text-danger ml-3"> 299.000 VNĐ</span>
        </div>
      </div>
    </div>
  );
};

export default ProducItem;
